import { PrismaClient } from "@prisma/client";

const prisma = new PrismaClient({
  datasources: { db: { url: process.env.DATABASE_URL } },
});

async function withRetry<T>(fn: () => Promise<T>, retries = 3, delay = 3000): Promise<T> {
  for (let i = 0; i < retries; i++) {
    try {
      return await fn();
    } catch (e: any) {
      if (i < retries - 1 && e?.message?.includes("Can't reach database")) {
        console.log(`  DB retry in ${delay/1000}s... (attempt ${i+2}/${retries})`);
        await new Promise(r => setTimeout(r, delay));
      } else throw e;
    }
  }
  throw new Error("Max retries reached");
}

type Q = {
  topic: string; year: number; questionText: string;
  optionA: string; optionB: string; optionC: string; optionD: string;
  correctOption: "A" | "B" | "C" | "D"; explanation: string;
  difficulty: "EASY" | "MEDIUM" | "HARD";
};

async function seedSubject(name: string, questions: Q[]) {
  const subject = await withRetry(() =>
    prisma.subject.findFirst({ where: { name, level: "SHS" } })
  );
  if (!subject) { console.log(`Subject ${name} not found!`); return; }
  let created = 0;
  for (const q of questions) {
    try {
      const existing = await withRetry(() =>
        prisma.question.findFirst({
          where: { subjectId: subject.id, year: q.year, questionText: q.questionText },
        })
      );
      if (existing) continue;
      await withRetry(() =>
        prisma.question.create({
          data: {
            level: "SHS", examType: "WASSCE", subjectId: subject.id,
            topic: q.topic, year: q.year, questionText: q.questionText,
            optionA: q.optionA, optionB: q.optionB, optionC: q.optionC, optionD: q.optionD,
            correctOption: q.correctOption, explanation: q.explanation,
            difficulty: q.difficulty as any,
          },
        })
      );
      created++;
    } catch (e) {}
  }
  console.log(`  ${name}: ${created}/${questions.length} created`);
}

